    project_id, directory_id, document_name, document_type, storage_key, version_no, source_type,
    uploaded_by, uploaded_time, file_size, checksum, compliance_status, archive_status, check_comment,
    deleted_flag, create_by, create_time, remark
) values (
    #{projectId}, #{directoryId}, #{documentName}, #{documentType}, #{storageKey}, #{versionNo}, #{sourceType},
    #{uploadedBy}, #{uploadedTime}, #{fileSize}, #{checksum}, #{complianceStatus}, #{archiveStatus}, #{checkComment},
    #{deletedFlag}, #{createBy}, sysdate(), #{remark}
)

mapper.update:
update inf_project_document
compliance_status = #{complianceStatus}, archive_status = #{archiveStatus}, check_comment = #{checkComment}, remark = #{remark}, update_by = #{updateBy}, update_time = sysdate()
